function AuthButtons() {
  const auth = useAuth();

  if (auth.isLoading) {
    return <div>Loading...</div>;
  }

  if (auth.error) {
    const hint = new URLSearchParams(window.location.search).get("error_hint");
    return (
      <div style={{ color: "red" }}>
        <p>Error: {auth.error.message}</p>
        {hint && <p>{hint}</p>}
        <button onClick={() => auth.signinRedirect()}>Try again</button>
      </div>
    );
  }

  if (auth.isAuthenticated) {
    return (
      <div>
        <p>
          Welcome, {auth.user?.profile.given_name}{" "}
          {auth.user?.profile.family_name} ({auth.user?.profile.email})
        </p>
        <button onClick={() => auth.signoutRedirect()}>Sign out</button>
      </div>
    );
  }

  return <button onClick={() => auth.signinRedirect()}>Sign in</button>;
}

export default function App() {
  return (
    <AuthProvider {...oidcConfig}>
      <h1>SecureAuth React PKCE Demo</h1>
      <AuthButtons />
    </AuthProvider>
  );
}

const userManager = new UserManager({
  authority: "{{ISSUER_URL}}",
  client_id: "{{CLIENT_ID}}",
  redirect_uri: "{{REDIRECT_URI}}",
  post_logout_redirect_uri: "{{POST_LOGOUT_URI}}",
  scope: "{{SCOPES}}",
});

const isLoading = ref(true);
const isAuthenticated = ref(false);
const user = ref<User | null>(null);
const error = ref<Error | null>(null);

let initialized = false;

async function initialize() {
  if (initialized) return;
  initialized = true;
  try {
    const params = new URLSearchParams(window.location.search);
    if (params.has("code") && params.has("state")) {
      const signedIn = await userManager.signinRedirectCallback();
      user.value = signedIn;
      isAuthenticated.value = true;
      window.history.replaceState({}, document.title, window.location.pathname);
    } else if (params.has("error")) {
      error.value = new Error(
        params.get("error_description") ??
          params.get("error") ??
          "Authentication failed",
      );
    } else {
      const existing = await userManager.getUser();
      if (existing && !existing.expired) {
        user.value = existing;
        isAuthenticated.value = true;
      }
    }
  } catch (err) {
    error.value = err instanceof Error ? err : new Error(String(err));
  } finally {
    isLoading.value = false;
  }
}

export function useAuth() {
  initialize();
  return {
    isLoading,
    isAuthenticated,
    user,
    error,
    signinRedirect: () => userManager.signinRedirect(),
    signoutRedirect: () => userManager.signoutRedirect(),
  };
}

